module watchdog_timer(  
    input wire clk,  
    input wire rst,  
    input wire enable,  
    input wire reset_signal,  
    output reg timeout  
);  
    parameter TIMEOUT_VALUE = 4'd10;  
    reg [3:0] unused_counter;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            unused_counter <= 4'd0;  
            timeout <= 1'b0;  
        end else if (enable) begin  
            if (reset_signal) begin  
                unused_counter <= 4'd0;  
                timeout <= 1'b0;  
            end else begin  
                if (unused_counter < TIMEOUT_VALUE) begin  
                    unused_counter <= unused_counter + 1;  
                end else begin  
                    timeout <= 1'b1;  
                end  
            end  
        end  
    end  
endmodule
